arguments.new_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // Breaking change: EF Core 9 applies each migration in its own transaction
    // and throws if Migrate() is called inside a user-initiated transaction.
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

